const socket = io();
const quill = new Quill('#editor-container', {
    theme: 'snow',
    modules: { toolbar: [[{ 'header': [1, 2, 3, false] }], ['bold', 'italic', 'underline', 'strike'], [{ 'color': [] }], [{ 'list': 'ordered'}, { 'list': 'bullet' }]] }
});
quill.on('text-change', (delta, oldDelta, source) => { if (source === 'user') { socket.emit('edit-script', quill.getContents()); } });
socket.on('update-script', (contents) => { quill.setContents(contents); });
const mediaUpload = document.getElementById('media-upload');
const mediaList = document.getElementById('media-list');
const videoTrack = document.getElementById('v-track-1');
const mainPreview = document.getElementById('main-preview');
let projectMedia = [];
mediaUpload.addEventListener('change', (e) => {
    const files = Array.from(e.target.files);
    files.forEach(file => {
        const fileURL = URL.createObjectURL(file);
        const mediaItem = { id: Date.now() + Math.random(), name: file.name, url: fileURL, type: file.type };
        projectMedia.push(mediaItem);
        const item = document.createElement('div');
        item.className = 'media-item';
        item.draggable = true;
        item.innerText = `📄 ${file.name.substring(0, 15)}...`;
        item.dataset.id = mediaItem.id;
        item.addEventListener('dragstart', (ev) => { ev.dataTransfer.setData('text/plain', mediaItem.id); });
        mediaList.appendChild(item);
    });
    socket.emit('update-project-media', projectMedia);
});
videoTrack.addEventListener('dragover', (e) => e.preventDefault());
videoTrack.addEventListener('drop', (e) => {
    e.preventDefault();
    const mediaId = e.dataTransfer.getData('text/plain');
    const media = projectMedia.find(m => m.id == mediaId);
    if (media) {
        const clip = document.createElement('div');
        clip.className = 'timeline-clip';
        clip.innerText = media.name;
        clip.style.width = '150px';
        clip.addEventListener('click', () => { mainPreview.src = media.url; mainPreview.play(); });
        videoTrack.appendChild(clip);
        sendTimelineUpdate();
    }
});
function sendTimelineUpdate() {
    const serializedTimeline = [];
    document.querySelectorAll('.timeline-clip').forEach(clip => { serializedTimeline.push({ text: clip.innerText, width: clip.style.width }); });
    socket.emit('update-timeline', serializedTimeline);
}
socket.on('update-timeline', (remoteTimeline) => {
    videoTrack.innerHTML = '';
    remoteTimeline.forEach(clipData => {
        const clip = document.createElement('div');
        clip.className = 'timeline-clip';
        clip.innerText = clipData.text;
        clip.style.width = clipData.width;
        videoTrack.appendChild(clip);
    });
});
socket.on('init-data', (data) => { if(data.script) quill.setContents(data.script); });
